import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { PlayerProvider } from './context/PlayerContext';
import Home from './pages/Home';
import Player from './components/Player';
// import Upload from './pages/Upload'; // Tạo sau

function App() {
  return (
    <PlayerProvider>
      <Router>
        <div className="App font-sans text-gray-900">
          {/* Navbar có thể đặt ở đây */}
          <nav className="bg-gray-900 text-white p-4 flex justify-between items-center">
            <h1 className="text-xl font-bold text-orange-500">Mini SoundCloud</h1>
            <div className="space-x-4">
                <button className="hover:text-orange-400">Home</button>
                <button className="hover:text-orange-400">Upload</button>
                <button className="hover:text-orange-400">Profile</button>
            </div>
          </nav>

          <Routes>
            <Route path="/" element={<Home />} />
            {/* <Route path="/upload" element={<Upload />} /> */}
          </Routes>

          {/* Player luôn hiển thị ở dưới */}
          <Player />
        </div>
      </Router>
    </PlayerProvider>
  );
}

export default App;
